import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/updating-fabric.1C0PZ95m.js";const o=JSON.parse(`{"title":"Updating Fabric on Linux","description":"A step-by-step guide on how to update Fabric on Linux.","frontmatter":{"title":"Updating Fabric on Linux","description":"A step-by-step guide on how to update Fabric on Linux.","authors":["IMB11","modmuss50"],"next":false,"files":[]},"headers":[],"relativePath":"players/updating-fabric/linux.md","filePath":"players/updating-fabric/linux.md","lastUpdated":1768516421000}`);var s={name:`players/updating-fabric/linux.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Updating Fabric on Linux <a class="header-anchor" href="#h1" aria-label="Permalink to “Updating Fabric on Linux”">​</a></h1><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Download the Fabric Installer <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Download the Fabric Installer”">​</a></h2><p>Download the <code>.jar</code> version of the Fabric Installer from the <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Fabric Website</a>, by clicking on <code>Download installer (Universal/.JAR)</code>.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Run the Fabric Installer <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Run the Fabric Installer”">​</a></h2><p>Close Minecraft and the Minecraft Launcher first before running the installer.</p><p>Open a terminal and run the installer using Java:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">java</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -jar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fabric-installer.jar</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Once you open the installer, you should see a screen like this:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Fabric Installer with &quot;Install&quot; highlighted" loading="lazy"></p><p>Make sure the new game version and Loader version are correct, then click <code>Install</code> to update Fabric.</p><div class="warning custom-block"><p class="custom-block-title">IMPORTANT</p><p>Make sure to uncheck &#39;Create Profile&#39; when running the installer!</p></div><h2 id="3-update-launcher-profile" tabindex="-1">3. Update Profile in the Minecraft Launcher <a class="header-anchor" href="#3-update-launcher-profile" aria-label="Permalink to “3. Update Profile in the Minecraft Launcher”">​</a></h2><p>Once installation completes, open the Minecraft Launcher. Then go to the <code>Installations</code> tab. Find your Fabric profile and open its edit screen:</p><p><img src="/assets/players/updating-fabric.png" alt="Updating Fabric Loader version in the Minecraft Launcher" loading="lazy"></p><p>Replace the version with the new version of Fabric Loader you just installed, and press <code>Save</code>.</p><h2 id="4-you-re-done" tabindex="-1">4. You&#39;re Done! <a class="header-anchor" href="#4-you-re-done" aria-label="Permalink to “4. You&#39;re Done!”">​</a></h2><p>Once you&#39;ve completed the steps you can go back to the <code>Play</code> tab, select the Fabric profile from the dropdown in the bottom-left corner and press play!</p><p>If you encounter any issues whilst following this guide, you can ask for help in the <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord</a> in the <code>#player-support</code> channel.</p>`,18)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};